var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어떤 선택이 적어도 부끄럼 없는 최후를 맞이할 수 있었는가.","JPN":"何を選べば、せめて恥ずかしくない最期を迎えられたのだろう。","ENG":"What choice could have led to a death without shame?","TWN":"哪種選擇能讓我迎來無愧於心的結局呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"몇 번이나 고민해봤지만 답은 나오지 않더군.","JPN":"何度も思い悩んだが、答えは出なかった。","ENG":"I've asked myself that countless times, but never found the answer.","TWN":"雖然考慮了很多次，但還是沒有答案。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"돌격해라! 놈들에게 달라붙지 못하면 이대로 당할 수밖에 없다!","JPN":"突撃しろ！　あいつらに接近できなければこのままやられてしまうだけだ！","ENG":"Charge! If we don't stop them, it'll be the end of us!","TWN":"攻擊！如果不能纏住那些傢伙，就只能這樣被動挨打！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_A","text":{"KOREA":"틀렸습니다! 화망이 워낙 두터운 나머지……!","JPN":"ダメです！　火網があまりにも強固で……！","ENG":"It won't work, sir! Their fire net is too–","TWN":"完，完了！火力太猛了……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"크헉……!?","JPN":"くはっ……！？","ENG":"Krrgh...?!","TWN":"呃……！？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"증원은! 어떻게 된 거냐! 어째서 증원을 부를 수 없는 거야!","JPN":"増援は！　どうなっている！　どうして増援が呼べないんだ！","ENG":"W-where's backup?! Why can't we call in more?!","TWN":"增援！怎麼回事！為什麼叫不了增援！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"구원자님……! 구원은, 우리를 구원해 주신다던 약속은……!","JPN":"救世主様……！　救いは、私たちを助けてくださるという約束は……！","ENG":"Savior...! Salvation, where's the promised salvation–?!","TWN":"救贖者大人……！我們的救贖在哪裡……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"세상에 원망 섞인 소리를 내뱉는 우리를, 그대는 어떤 심정으로 바라볼까.","JPN":"世界に対して恨みのこもった言葉を吐く私たちを、君はどんな気持ちで見ていたのだろう。","ENG":"I wonder, as we cry out our bitterness to the world, what must you think, watching us?","TWN":"對於這個世界發出怨恨之聲的我們，你會以怎樣的心情看待呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"흐릿해진 기억을 뒤져보지만… 애석하게도 그런 모습조차 떠올릴 수 없네.","JPN":"おぼろげになった記憶を手繰り寄せても……悲しいかな、そんな姿さえ思い出せない。","ENG":"I try to search my faded memories... but not even that image comes to mind.","TWN":"儘管翻找著模糊的記憶…… 可是就連模樣也回想不起來了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"저것이…… 현자가 감춰 둔 마지막 패인가?","JPN":"あれが……賢者が隠し持っていた最後のカードなのか？","ENG":"That... must be the wild card that the Sage kept hidden.","TWN":"那是……智者藏起來的最後一張牌嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 아무리 현자라도, 저런 괴물을 함부로 풀어 놓았다간……","JPN":"しかし、いくら賢者でも、あのような化け物を無闇に野放しにしては……","ENG":"But even for the Sage, letting loose a monster like that...","TWN":"不過就算是智者，釋放出那種怪物之後……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"버밍엄 교수님!","JPN":"バーミンガム教授！","ENG":"Professor Birmingham!","TWN":"伯明罕教授！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 알렌 버밍엄! 전황은 완전히 우리 측으로 넘어 왔다!","JPN":"いや、アレン・バーミンガム！　戦況は完全に私たちに傾いた！","ENG":"No, Allen Birmingham! The tides of war have clearly shifted towards our favor!","TWN":"不，艾倫·伯明罕！局勢完全偏向我們這邊了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"무기를 버리고 투항한다면 패자로서 예우해 주겠다!","JPN":"武器を捨て投降すれば、敗者として配慮してやる！","ENG":"Abandon your weapons and surrender now, and you will be treated with respect as a defeated enemy!","TWN":"放下武器投降的話，我會以禮待之！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……좋은 제안을 거절해서 미안하군. 슈발리에 단장.","JPN":"……良案を断ってしまい申し訳ない。シュヴァリエ団長。","ENG":"...I apologize for declining the generous offer, Captain Chevalier.","TWN":"……很抱歉拒絕你的這個提議，艾斯特洛索團長。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 내 마음은 처음부터 늘 같았다.","JPN":"私の心は最初から決まっている。","ENG":"But my heart has always been the same.","TWN":"我的心意自始至終都沒變過。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"우리가 걸었던 길을 답습하기만 해 봤자, 그 끝은 정해져 있어.","JPN":"我々がかつて歩んだ道を踏襲するだけでは、同じ結末を迎えてしまう。","ENG":"Repeating our past won't change anything.","TWN":"只要依循我們走過的路，結局就是註定的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"별의 인도자를, 우리를……","JPN":"星の導き手を、我々を……","ENG":"Following the Star Guide, and us–","TWN":"就算追隨星之引導者，我們也……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":" 컥!","JPN":"かはっ！","ENG":"Kuh!","TWN":"咳！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"염동력……?","JPN":"念動力……？","ENG":"Telekinesis...?","TWN":"這是念力……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"누구냐! 기사의 결투에 개입하는 자는!","JPN":"誰だ！　騎士の決闘に横やりを入れる者は！","ENG":"Who dare interrupts a knight's battle!","TWN":"是誰！為什麼要介入騎士之間的決鬥！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"괴물이, 이 거리에서…….","JPN":"怪物が、この距離で……","ENG":"The monster, plans to break my neck...","TWN":"那個怪物，是想在這個距離上……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"내 목을… 부러뜨릴 셈인가…!","JPN":"私の首を……折る気か…！","ENG":"From that distance...!","TWN":"弄斷……我的脖子嗎……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"불필요한 희생을 낼 이유는 없다. 마왕의 사도.","JPN":"不要な犠牲を出す必要はない。魔王の使徒。","ENG":"There is no need for unnecessary bloodshed, Apostle.","TWN":"沒有理由作出不必要的犧牲，魔王的使徒。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"<color=#ffd34c>이곳</color>에서라면, 저격은 확실하다.","JPN":"<color=#ffd34c>ここ</color>でなら、狙撃は確実だ。","ENG":"A clear shot is assured from <color=#ffd34c>here</color>.","TWN":"如果是在<color=#ffd34c>這個空間裡</color>，狙擊會很準確。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"마지막까지, 결국 아무것도 지키지 못했다.","JPN":"結局、最後まで何も守れなかった。","ENG":"In the end, I couldn't protect anything.","TWN":"直到最後，終究還是什麼都沒能守護住。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"사랑하는 여인, 전우들과의 맹세, 그리고… 길 잃고 헤매는 친구도.","JPN":"愛する人も、戦友たちとの誓いも、そして……迷える友も。","ENG":"Not the woman I loved, not the vows I made with my comrades, and... not even the friend who'd lost their way.","TWN":"心愛的女人，與戰友的誓言，還有……迷失方向的朋友。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"그 어떤 것도 지키지 못하고, 희망을 남길 기회조차 없다.","JPN":"何一つ守れず、希望を残す機会すら許されていない。","ENG":"I couldn't protect a single thing. And now, there's not even a chance to leave hope behind.","TWN":"什麼都無法守護，甚至沒有留下希望的機會。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"적어도 옳은 결정을 했다고 느낄 수 있게, 도우려 했는데.","JPN":"少なくとも、正しい決断をしたんだと君が思えるように、助けたかったんだが。","ENG":"I wanted you to feel that you've made the right choice, at least.","TWN":"我本想幫你，至少讓你覺得自己做了正確的決定。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"마지막까지……. 친구인 너에게 짐만 남겼구나.","JPN":"最後まで……友である君に背負わせてしまったな。","ENG":"Even in the last moment... I am leaving behind a burden to you, dear friend.","TWN":"結果到最後……還是對你造成了負擔，我的朋友。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"고향이, 아니. 아카데미가.","JPN":"故郷が、いや。アカデミーが。","ENG":"When your hometown, no, the academy...","TWN":"或許那個小鎮，不，學院。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"너의 안식처였는데도.","JPN":"君の安息の地だったのに。","ENG":"Was your sanctuary.","TWN":"才是你的避難之所。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……미안하다. 레이.","JPN":"……許してくれ、レイ。\xA0\xA0","ENG":"...I'm sorry, Ray.\xA0\xA0","TWN":"……對不起，雷伊。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그만해! 멈춰!!","JPN":"やめろ！　やめろお！！","ENG":"Stop! I said stop!","TWN":"住手！停下！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……에스테로사.","JPN":"……エステロサ。","ENG":"...Esterosa.","TWN":"……艾斯特洛索。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"신의를 배신한 괴물마저, 그대는 마지막까지 두둔하는가.","JPN":"君という人は、信義に背いた化け物であっても最後まで肩を持つのか。","ENG":"Even now, you defend the monster that betrayed your trust?","TWN":"連這背信忘義的怪物，你也要袒護到最後嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……물건이나 훔칠 줄 아는 양치기가 백작령에 도움이 될 지는 모르겠군요.","JPN":"……盗みくらいしかできない羊飼いが伯爵領のお役に立てるでしょうか。","ENG":"...I'm not sure what good a shepherd who only knows how to steal things could do for the County.","TWN":"……我不知道一個隻會偷東西的牧羊人能否對伯爵領地有所幫助。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"사욕을 부린 호위가 타인으로부터 빼앗은 물건이었지요.","JPN":"護衛が私利私欲を満たすために、他人から奪い取った物でしたね。","ENG":"It was one of my guards who stole, driven by greed.","TWN":"貪欲的護衛從他人那裡奪來的東西吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당신이 아니었다면, 재물에 취한 사람이 제 곁에 머물렀을 거고요.","JPN":"貴方がいなかったら、その貪欲な人間は今も私の側にいたはずです。","ENG":"If it weren't for you, I might've kept someone like that at my side.","TWN":"如果不是你，貪圖財富的人就會留在我身邊了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 전 평민에 불과합니다.","JPN":"ですが私は平民です。","ENG":"But I am just a commoner.","TWN":"但是我只是個平民而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"신분의 귀천은 중요하지 않습니다.","JPN":"身分が重要なのではありません。","ENG":"Status means nothing.","TWN":"身份的高低並不重要。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"진정 중요한 건… 그래요.","JPN":"本当に重要なのは……そう。","ENG":"What truly matters is... yes.","TWN":"真正重要的是……對。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어두운 밤에 길 잃고 헤매는 이들을 구원해줄, 그 내면의 찬란한 별빛이지요.","JPN":"闇夜で道に迷っている者たちを救う、その胸の内に輝く星の光です。","ENG":"The radiant starlight inside you, the kind that saves those lost in the night.","TWN":"是拯救在黑夜中迷失徘徊之人的內心璀璨星光。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……별빛.","JPN":"……星の光。","ENG":"...Starlight.","TWN":"……星光。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그런가.","JPN":"そうか。","ENG":"I see.","TWN":"是嗎。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"적어도… 하나 정도는 남긴 모양이군.","JPN":"せめて……一つぐらいは、残せたようだ。","ENG":"So at least... I managed to leave behind one thing.","TWN":"似乎至少留下了一個。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"안 돼, 제발…!!","JPN":"ダメだ……！！","ENG":"No, don't...!!","TWN":"不要，求你……！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"멈춰…!!","JPN":"止まって……！！","ENG":"Please, stop...!!","TWN":"停下…！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"조금 늦었지만, 지금이라면 얼굴을 마주볼 수 있을지 모른다는 생각이 드는군.","JPN":"遅くなってしまったが、今なら君とまともに向かい合える気がする。","ENG":"A bit late, but now I wonder if I'd be able to face you again.","TWN":"雖然有些遲了，但我覺得現在或許可以面對你了。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"오늘따라 그대가 보고 싶네.","JPN":"今日はなぜか、君にとても会いたい。","ENG":"Today of all days, I find myself missing you.","TWN":"今天特別想見你。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"……그레이스.","JPN":"……グレース。","ENG":"...Grace.","TWN":"……葛瑞絲。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"제국의 기사들은 기사도라는 명예를 갖춘 아주 고상한 존재였다.","JPN":"帝国の騎士たちは騎士道という名誉を備えた崇高な存在だった。","ENG":"The Imperial knights were once noble beings, proud of their chivalry.","TWN":"帝國的騎士們是擁有騎士精神這種榮譽的高尚存在。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"휘두르던 칼을 거두고, 피보다 진한 눈물로 존중을 야기하고.","JPN":"振り回していた剣を収め、血よりも濃い涙で互いを尊重し。","ENG":"They sheathed their swords, honored others through tears deeper than blood.","TWN":"收起揮舞的刀，以比血更濃的淚水引發尊重。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"앞서간 이들의 족적을 자신의 발자국으로 뒤덮는 것. 그것이 그들의 신념이었다.","JPN":"先立つ者たちの足跡に自分たちの足跡を重ねること。それが彼らの信念だった。","ENG":"To cover the steps of those who came before with their own footprints was their creed.","TWN":"用自己的足跡覆蓋前人的蹤跡。這就是他們的信念。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 철보다 차갑게 마모된 피를 뒤집어쓰고 투쟁을 위해 든 검에 비명이 걸렸을 때.","JPN":"しかし、鉄よりも冷たい血をかぶり、闘争のために掲げた剣に悲鳴が聞こえた時。","ENG":"But when their sword, drawn for battle, was soaked in blood colder than steel and cried out...","TWN":"但是當被比鐵更冷的血液覆蓋，為了鬥爭而舉起的劍上掛著尖叫聲時。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"그들은 긴 겨울에 길을 잃었음을 깨달았다.","JPN":"彼らは長い冬の中で道に迷ったことに気づいた。","ENG":"They realized they had lost their way in the long winter.","TWN":"他們意識到自己在漫長的冬季中迷失了方向。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"뒤돌아본 길에, 어느 발자국 하나 없다는 것도.","JPN":"振り向いた場所に足跡は残っていなかった。","ENG":"And that no footsteps remained on the path behind them.","TWN":"回頭看去，發現路上沒有一個腳印。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 아아…….","JPN":"あ、ああ……","ENG":"Ah... Aaaah...","TWN":"啊，啊啊……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아아아아…!!","JPN":"ああああ………！！","ENG":"Ahhhh...!!","TWN":"啊啊啊啊……！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"적막한 밤을 피워내는 겨울날.","JPN":"冬の日は寂寞とした夜を作り出す。","ENG":"On a winter's day that burned through the silence of night.","TWN":"點燃寂靜之夜的冬日。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"수많은 정의가, 그 속에 파묻혔다.","JPN":"数多くの正義が、その中に埋もれていった。","ENG":"Countless versions of justice were buried deep within the snow.","TWN":"無數的正義，被埋沒在其中。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};